mapper.sql:
WHERE ro.deleted_flag = #{queryForm.deletedFlag}

    AND (INSTR(ro.create_user_name ,#{queryForm.keywords}) OR
    INSTR(ro.receive_order_number,#{queryForm.keywords}) OR
    INSTR(roi.invoice_name,#{queryForm.keywords}) OR
    INSTR(tw.waybill_number,#{queryForm.keywords})
    )


    AND (INSTR(s.short_name, #{queryForm.consignor}) OR
    INSTR(s.consignor, #{queryForm.consignor}))


    and DATE_FORMAT(ro.business_date, '%Y-%m-01') >= DATE_FORMAT(#{queryForm.businessDateBegin},'%Y-%m-01')


    and DATE_FORMAT(ro.business_date, '%Y-%m-01') <= DATE_FORMAT(#{queryForm.businessDateEnd},'%Y-%m-01')


    AND ro.check_status = #{queryForm.checkStatus}


    AND ro.make_invoice_flag = #{queryForm.makeInvoiceFlag}


    AND ro.account_period_date < DATE_FORMAT(now(),'%Y-%m-%d')


    AND ro.account_period_date > DATE_FORMAT(now(),'%Y-%m-%d')


    AND ro.shipper_id = #{queryForm.shipperId}


    AND ro.invoice_status = #{queryForm.invoiceStatus}


    AND DATE_FORMAT(ro.account_period_date, '%Y-%m-%d') >= #{queryForm.accountPeriodStartTime}


    AND DATE_FORMAT(ro.account_period_date, '%Y-%m-%d') <= #{queryForm.accountPeriodEndTime}


    AND DATE_FORMAT(ro.create_time, '%Y-%m-%d') >= #{queryForm.createTime}


    AND DATE_FORMAT(ro.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


    AND ro.enterprise_id = #{queryForm.enterpriseId}


    AND ro.verification_flag = #{queryForm.verificationFlag}


    AND s.shipper_id in

        #{item}



    AND ro.create_user_id in

        #{item}



    AND sp.employee_id in

        #{item}



    and DATE_FORMAT(ro.business_date, '%Y-%m-01') >= date_format(#{queryForm.businessStartDate},'%Y-%m-01')


    and DATE_FORMAT(ro.business_date, '%Y-%m-01') <= date_format(#{queryForm.businessEndDate},'%Y-%m-01')

group by ro.receive_order_id

    ORDER BY ro.create_time DESC

mapper.select:
SELECT ro.receive_order_id, ro.receive_order_number, ro.shipper_id, ro.enterprise_id, ro.total_amount, ro.tax_point, ro.bill_attachment, ro.create_time, ro.create_user_name, roi.invoice_remark, roi.invoice_amount, roi.invoice_number, roi.invoice_no, roi.receive_order_invoice_id, roi.invoice_type, roi.invoice_kind_type , roi.invoice_user_id , roi.invoice_user_name , roi.invoice_name, roi.invoice_phone, roi.invoice_bank_name, roi.invoice_bank_no, roi.invoice_address, roi.invoice_time, roi.courier_number, roi.invoice_attachment, s.consignor, s.short_name, ro.business_date, ro.attachment FROM t_receive_order ro LEFT JOIN t_receive_order_invoice roi ON roi.receive_order_id = ro.receive_order_id LEFT JOIN t_shipper s ON ro.shipper_id = s.shipper_id
AND ( INSTR(ro.receive_order_number,#{queryForm.keywords}) OR INSTR(ro.create_user_name,#{queryForm.keywords}) OR INSTR(roi.invoice_name,#{queryForm.keywords}) )
AND INSTR(s.short_name,#{queryForm.consignor})
AND DATE_FORMAT(roi.invoice_time, '%Y-%m-%d') >= #{queryForm.invoiceStartTime}
AND DATE_FORMAT(roi.invoice_time, '%Y-%m-%d') <= #{queryForm.invoiceEndTime}
AND roi.invoice_status = #{queryForm.invoiceStatus}
AND ro.check_status = #{queryForm.checkStatus}
AND ro.make_invoice_flag = #{queryForm.makeInvoiceFlag}
AND ro.enterprise_id = #{queryForm.enterpriseId}
ORDER BY ro.create_time DESC

select ro.*
from t_receive_order ro
left join t_receive_order_waybill trow on trow.receive_order_id = ro.receive_order_id
where trow.waybill_id = #{waybillId} and ro.check_status != #{excludeCheckStatus}
and ro.invoice_status != #{excludeInvoiceStatus}

SELECT ro.receive_order_id, ro.receive_order_number, ro.freight, ro.total_amount, ro.abnormal_amount, ro.make_invoice_flag, ro.check_status, ro.check_remark, ro.invoice_status, ro.tax_point, ro.remark, ro.verification_flag, ro.check_attachment, ro.create_user_name, s.shipper_id, s.consignor, s.short_name, oe.enterprise_name, ro.account_period_date, ro.create_time, ro.business_date, ro.attachment FROM t_receive_order ro LEFT JOIN t_shipper s ON s.shipper_id = ro.shipper_id LEFT JOIN t_oa_enterprise oe ON oe.enterprise_id = ro.enterprise_id WHERE ro.deleted_flag = #{queryForm.deletedFlag}
AND ro.enterprise_id = #{queryForm.enterpriseId}
AND (INSTR(ro.create_user_name , #{queryForm.keywords}) OR INSTR(ro.receive_order_number, #{queryForm.keywords}))
AND ro.check_status = #{queryForm.checkStatus}
AND ro.shipper_id = #{queryForm.shipperId}
AND ro.invoice_status = #{queryForm.invoiceStatus}
AND DATE_FORMAT(ro.account_period_date, '%Y-%m-%d') >= #{queryForm.accountPeriodStartTime}
AND DATE_FORMAT(ro.account_period_date, '%Y-%m-%d') <= #{queryForm.accountPeriodEndTime}
ORDER BY ro.create_time DESC

SELECT waybill_id,business_date FROM t_receive_order ro LEFT JOIN t_receive_order_cost_item rooi ON ro.receive_order_id = rooi.receive_order_id where ro.check_status != #{excludeCheckStatus}
AND waybill_id in
#{item}
GROUP BY waybill_id

SELECT receiveList.* FROM ( SELECT ro.receive_order_id, ro.receive_order_number, ro.shipper_id, s.consignor, oe.enterprise_id, oe.enterprise_name, ro.make_invoice_flag, ro.total_amount as totalAmount, IFNULL(SUM(ror.verification_amount),0) as verificationAmount, ro.business_date, ro.account_period_date FROM t_receive_order ro LEFT JOIN t_shipper s ON ro.shipper_id = s.shipper_id LEFT JOIN t_shipper_principal sp on s.shipper_id = sp.shipper_id and sp.type = #{queryForm.shipperSaleType} LEFT JOIN t_oa_enterprise oe ON ro.enterprise_id = oe.enterprise_id LEFT JOIN t_receive_order_verification ror ON ror.receive_order_id = ro.receive_order_id WHERE ro.account_period_date IS NOT NULL AND ro.check_status = #{queryForm.checkStatus} AND ro.verification_flag = #{queryForm.verificationFlag} AND ro.invoice_status IN
#{item}
AND ( INSTR(ro.receive_order_number, #{queryForm.keyWords}) OR INSTR(s.consignor, #{queryForm.keyWords}) OR INSTR(s.short_name, #{queryForm.keyWords}))
AND sp.employee_id in
#{item}
AND ro.shipper_id = #{queryForm.shipperId}
AND DATE_FORMAT(ro.account_period_date, '%Y-%m-%d') >= DATE_FORMAT(#{queryForm.startDate}, '%Y-%m-%d')
AND DATE_FORMAT(ro.account_period_date, '%Y-%m-%d') <= DATE_FORMAT(#{queryForm.endDate}, '%Y-%m-%d')
AND ro.enterprise_id = #{queryForm.enterpriseId}
group by ro.receive_order_id ) as receiveList
receiveList.totalAmount != receiveList.verificationAmount
